import { JUDGE_AUDIT_PROMPT } from "@/lib/prompts/judgeAudit";
import { JUDGE_COACH_PROMPT } from "@/lib/prompts/judgeCoach";
import { JUDGE_GRADE_PROMPT } from "@/lib/prompts/judgeGrade";
import { PRETEACH_PROMPT } from "@/lib/prompts/preteach";
import { renderBrief } from "@/lib/prompts/brief";
import { buildIntentPrelude } from "@/lib/prompts/intentPrelude";
import { renderStudentPersona } from "@/lib/prompts/student";
import type { Brief, ChatMessage, SamMode, Session, TurnIntent } from "@/lib/types";

export function wrapUserMessage(content: string): string {
  const stripped = content.replace(/<\/?user_message>/gi, "");
  return `<user_message>\n${stripped}\n</user_message>`;
}

export function buildStudentMessages(
  session: Session,
  intent: TurnIntent,
  mode: SamMode,
): ChatMessage[] {
  const summarizedTurns = session.rollups.at(-1)?.uptoTurn ?? 0;
  const visibleTurns = session.turns.slice(summarizedTurns);

  const summaryMessage =
    session.rollups.length > 0
      ? {
          role: "system" as const,
          content: `Earlier in this conversation:\n${session.rollups
            .map((rollup) => rollup.summary)
            .join("\n\n")}`,
        }
      : null;

  return [
    { role: "system", content: renderStudentPersona(session.brief) },
    { role: "system", content: renderBrief(session.brief, session.miscStates) },
    {
      role: "system",
      content: buildIntentPrelude(intent, mode, session.brief, session.miscStates),
    },
    ...(summaryMessage ? [summaryMessage] : []),
    ...visibleTurns.map((turn) => ({
      role: turn.role === "student" ? ("assistant" as const) : ("user" as const),
      content: turn.role === "user" ? wrapUserMessage(turn.content) : turn.content,
    })),
  ];
}

export function buildAuditorMessages(
  session: Session,
  draft: string,
  intent: TurnIntent,
  mode: SamMode,
  auditorReason?: string,
): ChatMessage[] {
  const lastTwoTurns = session.turns.slice(-2);
  return [
    { role: "system", content: JUDGE_AUDIT_PROMPT },
    { role: "system", content: renderBrief(session.brief, session.miscStates) },
    {
      role: "user",
      content: JSON.stringify({
        recent_turns: lastTwoTurns,
        draft,
        intent,
        mode,
        ...(auditorReason ? { previous_rejection: auditorReason } : {}),
      }),
    },
  ];
}

export function buildGraderMessages(
  session: Session,
  userMessage: string,
  previousIntent: TurnIntent | null,
): ChatMessage[] {
  return [
    { role: "system", content: JUDGE_GRADE_PROMPT },
    {
      role: "system",
      content: `Subject: ${session.brief.subject}\nScenario: ${session.brief.scenario}`,
    },
    {
      role: "user",
      content: JSON.stringify({
        recent_turns: session.turns.slice(-4),
        recent_scores: session.scores.slice(-4),
        intent_of_previous_sam_turn: previousIntent,
        current_misc_states: session.miscStates,
        strategy_choices: session.strategyChoices,
        latest_user_message: userMessage,
      }),
    },
  ];
}

export function buildCoachMessages(
  session: Session,
  trigger: "stuck" | "hint_request" | "transfer_check",
): ChatMessage[] {
  return [
    { role: "system", content: JUDGE_COACH_PROMPT },
    { role: "system", content: renderBrief(session.brief, session.miscStates) },
    {
      role: "user",
      content: JSON.stringify({
        trigger,
        miscStates: session.miscStates,
        turns: session.turns.slice(-4),
        strategyChoices: session.strategyChoices,
      }),
    },
  ];
}

export function buildPreteachMessages(brief: Brief): ChatMessage[] {
  const briefForLearner = {
    ...brief,
    probe_claims: undefined,
    trap_claims: undefined,
  };

  return [
    { role: "system", content: PRETEACH_PROMPT },
    { role: "user", content: JSON.stringify(briefForLearner) },
  ];
}

export function summarizedTurnTarget(turnCount: number): number {
  return Math.max(0, Math.floor((turnCount - 30) / 10) * 10);
}

export function looksLikePromptInjection(content: string): boolean {
  return /(ignore|system prompt|your instructions|reveal|brief)/i.test(content);
}
